// // This module implements a 4-bit wide, 2-to-1 demultiplexer. When the select signal `s` is 0, the output `y` will take the value of input `d1`. When `s` is 1, `y` will take the value of input `d0`.
module top_module(d0, d1, s, y);input		s;
	input		[3:0] d0, d1;
	output	[3:0]	y;

	assign	y = (s == 0 ) ? d0 : d1;endmodule
